37	
38	@Controller("/api/brain")
39	public class BrainController {
40	
41	    private Path getBrainPath(String flavor) {
42	        if (flavor == null || flavor.isEmpty()) flavor = "antigravity-cli";
43	        return Paths.get(System.getProperty("user.home"), ".gemini", flavor, "brain");
44	    }
45	
46	    @ExecuteOn(TaskExecutors.IO)
47	    @Get("/conversations")
48	    public List<Map<String, String>> listConversations(@QueryValue Optional<String> flavor) {
49	        Path brainPath = getBrainPath(flavor.orElse("antigravity-cli"));
50	        if (!Files.exists(brainPath)) return List.of();
51	
52	        try (Stream<Path> paths = Files.list(brainPath)) {
53	            return paths
54	                .filter(p -> {
55	                    if (!Files.isDirectory(p)) return false;
56	                    Path transcriptPath = p.resolve(".system_generated/logs/transcript.jsonl");
57	                    if (!Files.exists(transcriptPath)) return false;
58	                    try {
59	                        return Files.size(transcriptPath) > 0;
60	                    } catch (IOException e) {
61	                        return false;
62	                    }
63	                })
64	                .map(p -> {
65	                    String id = p.getFileName().toString();
66	                    Map<String, String> info = new HashMap<>();
67	                    info.put("id", id);
68	
69	                    String summary = "Conversation " + id.substring(0, 8);
70	                    Path shortTitlePath = p.resolve(".system_generated/logs/short_title.txt");
71	                    if (Files.exists(shortTitlePath)) {
72	                        try {
73	                            summary = Files.readString(shortTitlePath).trim();
74	                        } catch (IOException e) {}
75	                    } else {
76	                        Path transcriptPath = p.resolve(".system_generated/logs/transcript.jsonl");
77	                        if (Files.exists(transcriptPath)) {
78	                            try (BufferedReader reader = Files.newBufferedReader(transcriptPath)) {
79	                                ObjectMapper mapper = new ObjectMapper();
80	                                String line;
81	                                while ((line = reader.readLine()) != null) {
82	                                    if (line.contains("\"USER_INPUT\"")) {
83	                                        Map<String, Object> map = mapper.readValue(line, Map.class);
84	                                        if ("USER_INPUT".equals(map.get("type"))) {
85	                                            String content = (String) map.getOrDefault(
86	                                                "content",
87	                                                ""
88	                                            );
89	                                            content =
90	                                                content.replaceAll("(?s)<USER_REQUEST>\\s*", "");
91	                                            int endIdx = content.indexOf("</USER_REQUEST>");
92	                                            if (endIdx != -1) {
93	                                                content = content.substring(0, endIdx);
94	                                            }
95	                                            content = content.trim();
96	                                            if (content.length() > 80) {
97	                                                content = content.substring(0, 80) + "...";
98	                                            }
99	                                            if (!content.isEmpty()) {
100	                                                summary = content;
101	                                            }
102	                                            break;
103	                                        }
104	                                    }
105	                                }
106	                            } catch (Exception e) {}
107	                        }
108	                    }
109	
110	                    info.put("summary", summary);
111	                    try {
112	                        Path transcriptPath = p.resolve(".system_generated/logs/transcript.jsonl");
113	                        long modified = Files.getLastModifiedTime(transcriptPath).toMillis();
114	                        info.put("updatedAt", String.valueOf(modified));
115	                    } catch (IOException e) {
116	                        info.put("updatedAt", "0");
117	                    }
118	                    return info;
119	                })
120	                .sorted((a, b) ->
121	                    Long.compare(
122	                        Long.parseLong(b.get("updatedAt")),
123	                        Long.parseLong(a.get("updatedAt"))
124	                    )
125	                )
126	                .collect(Collectors.toList());
127	        } catch (IOException e) {
128	            e.printStackTrace();
129	            return List.of();
130	        }
131	    }
132	
133	    @ExecuteOn(TaskExecutors.IO)
134	    @Get(value = "/conversations/{id}/transcript", produces = "application/json")
135	    public String getTranscript(@PathVariable String id, @QueryValue Optional<String> flavor)
136	        throws IOException {
137	        Path brainPath = getBrainPath(flavor.orElse("antigravity-cli"));
138	        Path transcriptPath = brainPath
139	            .resolve(id)
140	            .resolve(".system_generated/logs/transcript_full.jsonl");
141	        if (!Files.exists(transcriptPath)) {
142	            transcriptPath =
143	                brainPath.resolve(id).resolve(".system_generated/logs/transcript.jsonl");
144	        }
145	        if (!Files.exists(transcriptPath)) {
146	            return "[]";
147	        }
148	
149	        // Read JSONL and convert to a JSON array of objects
150	        try (Stream<String> lines = Files.lines(transcriptPath)) {
151	            String jsonArray = lines
152	                .map(String::trim)
153	                .filter(line -> !line.isEmpty())
154	                .collect(Collectors.joining(",", "[", "]"));
155	            return jsonArray;
156	        }
157	    }
158	
159	    @ExecuteOn(TaskExecutors.IO)
160	    @Get(value = "/file", produces = "text/plain")
161	    public HttpResponse<String> getFileContent(@QueryValue String path) {
162	        try {
163	            Path filePath = Paths.get(path).normalize();
164	            Path geminiDir = Paths.get(System.getProperty("user.home"), ".gemini").normalize();
165	            if (!filePath.startsWith(geminiDir)) {
166	                return HttpResponse.unauthorized();
167	            }
168	            if (Files.exists(filePath) && !Files.isDirectory(filePath)) {
169	                return HttpResponse.ok(Files.readString(filePath));
170	            } else {
171	                return HttpResponse.notFound("File not found or is a directory.");
172	            }
173	        } catch (IOException e) {
174	            return HttpResponse.serverError("Error reading file: " + e.getMessage());
175	        }
176	    }
177	}
