16	import {
17	  state,
18	  escapeHtml,
19	  updateTranscriptFilter,
20	  formatTime,
21	} from "./utils.js";
22	
23	export function renderStats(steps) {
24	  const container = document.getElementById("session-stats-container");
25	  if (!container) return;
26	
27	  if (!steps || steps.length === 0) {
28	    container.classList.add("hidden");
29	    return;
30	  }
31	  container.classList.remove("hidden");
32	
33	  let toolsCalled = 0;
34	  let userQueries = 0;
35	  let errors = 0;
36	  let modelResponses = 0;
37	  let toolFrequencies = {};
38	  let errorFrequencies = {};
39	  let segments = [];
40	  let currentSegment = null;
41	  const sortedSteps = [...steps]
42	    .filter((s) => s.created_at)
43	    .sort(
44	      (a, b) =>
45	        new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
46	    );
47	  const getStepEndTime = (step) => {
48	    let t = new Date(step.created_at).getTime();
49	    if (step.content) {
50	      const match = step.content.match(/Completed At:\s*([^\n]+)/);
51	      if (match && match[1]) {
52	        const c = new Date(match[1].trim()).getTime();
53	        if (!isNaN(c)) t = Math.max(t, c);
54	      }
55	    }
56	    return t;
57	  };
58	
59	  sortedSteps.forEach((step) => {
60	    const t = new Date(step.created_at).getTime();
61	    const endT = getStepEndTime(step);
62	    const isUserStep =
63	      step.source === "USER_EXPLICIT" || step.type === "USER_INPUT";
64	    if (isUserStep || !currentSegment) {
65	      if (currentSegment) {
66	        segments.push(currentSegment);
67	      }
68	      currentSegment = { start: t, end: endT, steps: 1 };
69	    } else {
70	      currentSegment.end = Math.max(currentSegment.end, endT);
71	      currentSegment.steps++;
72	    }
73	  });
74	  if (currentSegment) {
75	    segments.push(currentSegment);
76	  }
77	
78	  steps.forEach((step) => {
79	    if (step.tool_calls && step.tool_calls.length > 0) {
80	      toolsCalled += step.tool_calls.length;
81	      step.tool_calls.forEach((tool) => {
82	        let toolName = tool.name || tool.function?.name || "unknown_tool";
83	        toolFrequencies[toolName] = (toolFrequencies[toolName] || 0) + 1;
84	      });
85	    } else if (
86	      step.type &&
87	      (step.type.includes("TOOL") ||
88	        step.type.includes("VIEW_FILE") ||
89	        step.type.includes("COMMAND"))
90	    ) {
91	      toolsCalled++;
92	    }
93	    if (step.source === "USER_EXPLICIT" || step.type === "USER_INPUT") {
94	      userQueries++;
95	    }
96	    if (
97	      step.source === "MODEL" &&
98	      (step.type === "PLANNER_RESPONSE" || step.type === "MESSAGE") &&
99	      step.content &&
100	      (!step.tool_calls || step.tool_calls.length === 0)
101	    ) {
102	      modelResponses++;
103	    }
104	    const isErrorStep =
105	      step.status === "ERROR" ||
106	      step.type === "ERROR_MESSAGE" ||
107	      (step.type === "RUN_COMMAND" &&
108	        step.content &&
109	        step.content.includes("The command failed"));
110	    if (isErrorStep) {
111	      errors++;
112	
113	      let errMsg = "Unknown Error";
114	      if (step.type === "RUN_COMMAND") {
115	        errMsg = "Command execution failed";
116	      } else {
117	        let source = step.error || step.content || "";
118	        let lines = source
119	          .split("\n")
120	          .map((l) => l.trim())
121	          .filter(
122	            (l) =>
123	              l &&
124	              !l.startsWith("Created At:") &&
125	              !l.startsWith("Completed At:")
126	          );
127	        if (lines.length > 0) {
128	          errMsg = lines[0];
129	          const prefix = "Encountered error in step execution: ";
130	          if (errMsg.startsWith(prefix)) {
131	            errMsg = errMsg.substring(prefix.length).trim();
132	          }
133	          errMsg = errMsg.substring(0, 100);
134	        }
135	      }
136	
137	      errorFrequencies[errMsg] = (errorFrequencies[errMsg] || 0) + 1;
138	    }
139	  });
140	
141	  let durationStr = "0s";
142	  if (segments.length > 0) {
143	    const diffMs = segments[segments.length - 1].end - segments[0].start;
144	    const diffSecs = Math.floor(diffMs / 1000);
145	    const diffMins = Math.floor(diffSecs / 60);
146	    const diffHours = Math.floor(diffMins / 60);
147	
148	    if (diffHours > 0) {
149	      durationStr = `${diffHours}h ${diffMins % 60}m`;
150	    } else if (diffMins > 0) {
151	      durationStr = `${diffMins}m ${diffSecs % 60}s`;
152	    } else {
153	      durationStr = `${diffSecs}s`;
154	    }
155	  }
156	
157	  let durationChartHtml =
158	    '<div class="tools-chart" id="duration-chart" style="display: none; margin-top: 24px; padding-top: 16px; border-top: 1px solid var(--border-color);">';
159	  durationChartHtml +=
160	    '<div style="font-size: 0.75rem; font-weight: 700; color: #f59e0b; margin-bottom: 16px; letter-spacing: 0.05em; text-transform: uppercase;">Session Timeline</div>';
161	
162	  if (segments.length === 0) {
163	    durationChartHtml += '<div class="stat-sub">No active segments</div>';
164	  } else {
165	    const totalMs = segments[segments.length - 1].end - segments[0].start;
166	    window.timelineStart = segments[0].start;
167	    window.timelineTotalMs = totalMs;
168	
169	    const bottomMarker = document.getElementById("timeline-bottom-marker");
170	    if (bottomMarker) {
171	      bottomMarker.dataset.timestamp =
172	        window.timelineStart + window.timelineTotalMs;
173	    }
174	
175	    let totalPausedMs = 0;
176	    let totalActiveMs = 0;
177	    segments.forEach((seg) => (totalActiveMs += seg.end - seg.start));
178	    if (segments.length > 1) {
179	      for (let i = 1; i < segments.length; i++) {
180	        totalPausedMs += segments[i].start - segments[i - 1].end;
181	      }
182	    }
183	
184	    const formatMs = (ms) => {
185	      const secs = Math.floor(ms / 1000);
186	      const mins = Math.floor(secs / 60);
187	      const hrs = Math.floor(mins / 60);
188	      if (hrs > 0) return `${hrs}h ${mins % 60}m`;
189	      if (mins > 0) return `${mins}m ${secs % 60}s`;
190	      return `${secs}s`;
191	    };
192	
193	    const defaultSummary = `<span>Active: <strong style="color:var(--text-primary);">${
194	      formatMs(totalActiveMs) === "0s" ? "Instant" : formatMs(totalActiveMs)
195	    }</strong></span><span>Paused: <strong style="color:var(--text-primary);">${formatMs(
196	      totalPausedMs
197	    )}</strong></span>`;
198	
199	    durationChartHtml +=
200	      '<div style="position: relative; height: 24px; width: 100%; background: rgba(30, 41, 59, 0.4); border-radius: 6px; overflow: hidden; border: 1px solid rgba(255,255,255,0.05);">';
201	
202	    if (totalMs === 0) {
203	      durationChartHtml += `<div style="position: absolute; left: 0%; width: 100%; height: 100%; background: #f59e0b;" onmouseover="const el=document.getElementById('timeline-hover-info'); el.innerHTML='<span style=\\'color:#f59e0b;\\'>Instant action</span>';" onmouseout="const el=document.getElementById('timeline-hover-info'); el.innerHTML=el.getAttribute('data-default');"></div>`;
204	    } else {
205	      let lastEnd = segments[0].start;
206	      segments.forEach((seg, index) => {
207	        const gapMs = seg.start - lastEnd;
208	        if (gapMs > 0) {
209	          const gapStartPct =
210	            ((lastEnd - window.timelineStart) / totalMs) * 100;
211	          const gapPct = (gapMs / totalMs) * 100;
212	          const gapStartStr = formatTime(lastEnd, false);
213	          const gapEndStr = formatTime(seg.start, false);
214	          const gapLenStr = formatMs(gapMs);
215	          const hoverText = `<span style=\\'color:var(--text-secondary);\\'>Pause: ${gapStartStr} - ${gapEndStr} (<strong style=\\'color:var(--text-primary);\\'>${gapLenStr}</strong>)</span>`;
216	          durationChartHtml += `<div style="position: absolute; left: ${gapStartPct}%; width: ${gapPct}%; height: 100%; background: transparent; cursor: pointer; transition: background 0.2s;" onclick="if(window.scrollToTime) { const pct = event.offsetX / this.offsetWidth; window.scrollToTime(${lastEnd} + pct * ${gapMs}); }" onmouseover="this.style.background='rgba(255,255,255,0.05)'; const el=document.getElementById('timeline-hover-info'); el.innerHTML='${hoverText}';" onmouseout="this.style.background='transparent'; const el=document.getElementById('timeline-hover-info'); el.innerHTML=el.getAttribute('data-default');"></div>`;
217	        }
218	
219	        const segMs = seg.end - seg.start;
220	        const segStartPct =
221	          ((seg.start - window.timelineStart) / totalMs) * 100;
222	        const segPct = (segMs / totalMs) * 100;
223	
224	        const startStr = formatTime(seg.start, false);
225	        const endStr = formatTime(seg.end, false);
226	        let lenStr = "Instant";
227	        if (segMs > 0) {
228	          const diffSecs = Math.floor(segMs / 1000);
229	          const diffMins = Math.floor(diffSecs / 60);
230	          const diffHours = Math.floor(diffMins / 60);
231	          if (diffHours > 0) lenStr = `${diffHours}h ${diffMins % 60}m`;
232	          else if (diffMins > 0) lenStr = `${diffMins}m ${diffSecs % 60}s`;
233	          else lenStr = `${diffSecs}s`;
234	        }
235	
236	        const hoverText = `<span style=\\'color:#f59e0b;\\'>Sequence: ${startStr} - ${endStr} (<strong style=\\'color:var(--text-primary);\\'>${lenStr}</strong>)</span>`;
237	        const leftCss = `calc(${segStartPct}% - ${(segStartPct / 100) * 2}px)`;
238	        durationChartHtml += `<div style="position: absolute; left: ${leftCss}; width: ${segPct}%; min-width: 2px; height: 100%; background: #f59e0b; cursor: pointer; transition: opacity 0.2s; opacity: 0.8;" onclick="if(window.scrollToTime) { const pct = event.offsetX / Math.max(this.offsetWidth, 2); window.scrollToTime(${seg.start} + pct * ${segMs}); }" onmouseover="this.style.opacity=1; const el=document.getElementById('timeline-hover-info'); el.innerHTML='${hoverText}';" onmouseout="this.style.opacity=0.8; const el=document.getElementById('timeline-hover-info'); el.innerHTML=el.getAttribute('data-default');"></div>`;
239	
240	        lastEnd = seg.end;
241	      });
242	    }
243	    durationChartHtml += `<div id="session-timeline-indicator" style="position: absolute; top: 0; bottom: 0; left: 0%; width: 0%; background: rgba(255, 255, 255, 0.2); border: 1px solid rgba(255, 255, 255, 0.5); box-sizing: border-box; border-radius: 4px; pointer-events: none; transition: left 0.1s ease-out, width 0.1s ease-out; display: none; z-index: 10;"></div>`;
244	    durationChartHtml += "</div>";
245	
246	    durationChartHtml += `<div id="timeline-hover-info" data-default='${defaultSummary}' style="display: flex; justify-content: space-between; margin-top: 12px; font-size: 0.8rem; color: var(--text-secondary); transition: all 0.2s;">${defaultSummary}</div>`;
247	  }
248	  durationChartHtml += "</div>";
249	
250	  const sortedTools = Object.entries(toolFrequencies).sort(
251	    (a, b) => b[1] - a[1]
252	  );
253	  let toolsChartHtml =
254	    '<div class="tools-chart" id="tools-chart" style="display: none; margin-top: 24px; padding-top: 16px; border-top: 1px solid var(--border-color);">';
255	  toolsChartHtml +=
256	    '<div style="font-size: 0.75rem; font-weight: 700; color: var(--text-secondary); margin-bottom: 16px; letter-spacing: 0.05em; text-transform: uppercase;">Tool Distribution</div>';
257	
258	  if (sortedTools.length === 0) {
259	    toolsChartHtml += '<div class="stat-sub">No tools called</div>';
260	  } else {
261	    const maxFreq = sortedTools[0][1];
262	    sortedTools.forEach(([name, count]) => {
263	      const width = Math.max((count / maxFreq) * 100, 2);
264	      toolsChartHtml += `
265	                <div class="tool-chart-row" style="display: flex; align-items: center; margin-bottom: 10px; gap: 16px;">
266	                    <div style="flex: 0 0 200px; font-size: 0.8rem; font-family: var(--font-mono); color: var(--text-primary); text-align: right; text-overflow: ellipsis; overflow: hidden; white-space: nowrap;" title="${name}">${name}</div>
267	                    <div style="flex: 1; height: 8px; background: rgba(30, 41, 59, 0.5); border-radius: 4px; overflow: hidden;">
268	                        <div style="height: 100%; width: ${width}%; background: var(--accent-purple); border-radius: 4px; transition: width 0.5s ease;"></div>
269	                    </div>
270	                    <div style="flex: 0 0 30px; font-size: 0.85rem; color: var(--text-secondary); font-weight: 600;">${count}</div>
271	                </div>
272	            `;
273	    });
274	  }
275	  toolsChartHtml += "</div>";
276	
277	  const sortedErrors = Object.entries(errorFrequencies).sort(
278	    (a, b) => b[1] - a[1]
279	  );
280	  let errorsChartHtml =
281	    '<div class="tools-chart" id="errors-chart" style="display: none; margin-top: 24px; padding-top: 16px; border-top: 1px solid var(--border-color);">';
282	  errorsChartHtml +=
283	    '<div style="font-size: 0.75rem; font-weight: 700; color: var(--error); margin-bottom: 16px; letter-spacing: 0.05em; text-transform: uppercase;">Issues Breakdown</div>';
284	
285	  if (sortedErrors.length === 0) {
286	    errorsChartHtml += '<div class="stat-sub">No issues detected</div>';
287	  } else {
288	    const maxErrFreq = sortedErrors[0][1];
289	    sortedErrors.forEach(([name, count]) => {
290	      const width = Math.max((count / maxErrFreq) * 100, 2);
291	      errorsChartHtml += `
292	                <div class="tool-chart-row" style="display: flex; align-items: center; margin-bottom: 10px; gap: 16px;">
293	                    <div style="flex: 0 0 300px; font-size: 0.8rem; font-family: var(--font-mono); color: var(--text-primary); text-align: right; text-overflow: ellipsis; overflow: hidden; white-space: nowrap;" title="${escapeHtml(
294	                      name
295	                    )}">${escapeHtml(name)}</div>
296	                    <div style="flex: 1; height: 8px; background: rgba(30, 41, 59, 0.5); border-radius: 4px; overflow: hidden;">
297	                        <div style="height: 100%; width: ${width}%; background: var(--error); border-radius: 4px; transition: width 0.5s ease;"></div>
298	                    </div>
299	                    <div style="flex: 0 0 30px; font-size: 0.85rem; color: var(--text-secondary); font-weight: 600;">${count}</div>
300	                </div>
301	            `;
302	    });
303	  }
304	  errorsChartHtml += "</div>";
305	
306	  container.innerHTML = `
307	        <div class="stats-grid">
308	            <div class="stat-card" id="errors-stat-card" style="cursor: ${
309	              errors > 0 ? "pointer" : "default"
310	            };">
311	                <div class="stat-label" style="display:flex; justify-content:space-between; align-items:center;">
312	                    OUTCOME
313	                    <span id="errors-chevron" class="chevron" style="display: ${
314	                      errors > 0 ? "inline-block" : "none"
315	                    };">›</span>
316	                </div>
317	                <div class="stat-value" style="color: ${
318	                  errors === 0 ? "var(--success)" : "var(--error)"
319	                };">
320	                    ${errors === 0 ? "Succeeded" : "Issues Detected"}
321	                </div>
322	                <div class="stat-sub">${errors} errors during execution</div>
323	            </div>
324	            <div class="stat-card" id="duration-stat-card" style="cursor: pointer;">
325	                <div class="stat-label" style="display:flex; justify-content:space-between; align-items:center;">
326	                    DURATION
327	                    <span id="duration-chevron" class="chevron">›</span>
328	                </div>
329	                <div class="stat-value" style="color: #f59e0b;">${durationStr}</div>
330	                <div class="stat-sub">${segments.length} active segment${
331	    segments.length !== 1 ? "s" : ""
332	  }</div>
333	            </div>
334	            <div class="stat-card" id="user-queries-stat-card" style="cursor: pointer;">
335	                <div class="stat-label" style="display:flex; justify-content:space-between; align-items:center;">
336	                    USER QUERIES
337	                    <span id="user-queries-chevron" class="chevron" style="display: inline-block; transform: rotate(0deg);">›</span>
338	                </div>
339	                <div class="stat-value">${userQueries}</div>
340	                <div class="stat-sub">Manual interactions</div>
341	            </div>
342	            <div class="stat-card" id="tools-stat-card" style="cursor: pointer;">
343	                <div class="stat-label" style="display:flex; justify-content:space-between; align-items:center;">
344	                    TOOLS CALLED
345	                    <span id="tools-chevron" class="chevron">›</span>
346	                </div>
347	                <div class="stat-value">${toolsCalled}</div>
348	                <div class="stat-sub">Agent-driven actions</div>
349	            </div>
350	            <div class="stat-card" id="model-responses-stat-card" style="cursor: pointer;">
351	                <div class="stat-label" style="display:flex; justify-content:space-between; align-items:center;">
352	                    MODEL RESPONSES
353	                    <span id="model-responses-chevron" class="chevron" style="display: inline-block; transform: rotate(0deg);">›</span>
354	                </div>
355	                <div class="stat-value">${modelResponses}</div>
356	                <div class="stat-sub">Agent answers</div>
357	            </div>
358	        </div>
359	        ${toolsChartHtml}
360	        ${errorsChartHtml}
361	        ${durationChartHtml}
362	    `;
363	
364	  const userCard = document.getElementById("user-queries-stat-card");
365	  if (userCard) {
366	    userCard.addEventListener("click", () => {
367	      const chevron = document.getElementById("user-queries-chevron");
368	      state.activeFilters.userQueries = !state.activeFilters.userQueries;
369	
370	      if (state.activeFilters.userQueries) {
371	        chevron.style.transform = "rotate(90deg)";
372	        userCard.style.borderColor = "var(--accent-blue)";
373	      } else {
374	        chevron.style.transform = "rotate(0deg)";
375	        userCard.style.borderColor = "var(--border-color)";
376	      }
377	      if (updateTranscriptFilter) updateTranscriptFilter();
378	    });
379	  }
380	
381	  const modelCard = document.getElementById("model-responses-stat-card");
382	  if (modelCard) {
383	    modelCard.addEventListener("click", () => {
384	      const chevron = document.getElementById("model-responses-chevron");
385	      state.activeFilters.modelResponses = !state.activeFilters.modelResponses;
386	
387	      if (state.activeFilters.modelResponses) {
388	        chevron.style.transform = "rotate(90deg)";
389	        modelCard.style.borderColor = "#a78bfa";
390	      } else {
391	        chevron.style.transform = "rotate(0deg)";
392	        modelCard.style.borderColor = "var(--border-color)";
393	      }
394	      if (updateTranscriptFilter) updateTranscriptFilter();
395	    });
396	  }
397	
398	  const toolsCard = document.getElementById("tools-stat-card");
399	  if (toolsCard) {
400	    toolsCard.addEventListener("click", () => {
401	      const chart = document.getElementById("tools-chart");
402	      const chevron = document.getElementById("tools-chevron");
403	      state.activeFilters.toolsCalled = !state.activeFilters.toolsCalled;
404	
405	      if (state.activeFilters.toolsCalled) {
406	        chart.style.display = "block";
407	        chevron.style.transform = "rotate(90deg)";
408	        toolsCard.style.borderColor = "var(--accent-purple)";
409	      } else {
410	        chart.style.display = "none";
411	        chevron.style.transform = "rotate(0deg)";
412	        toolsCard.style.borderColor = "var(--border-color)";
413	      }
414	      if (updateTranscriptFilter) updateTranscriptFilter();
415	    });
416	  }
417	
418	  const errorsCard = document.getElementById("errors-stat-card");
419	  if (errorsCard && errors > 0) {
420	    errorsCard.addEventListener("click", () => {
421	      const chart = document.getElementById("errors-chart");
422	      const chevron = document.getElementById("errors-chevron");
423	      state.activeFilters.outcomeErrors = !state.activeFilters.outcomeErrors;
424	
425	      if (state.activeFilters.outcomeErrors) {
426	        chart.style.display = "block";
427	        chevron.style.transform = "rotate(90deg)";
428	        errorsCard.style.borderColor = "var(--error)";
429	      } else {
430	        chart.style.display = "none";
431	        chevron.style.transform = "rotate(0deg)";
432	        errorsCard.style.borderColor = "var(--border-color)";
433	      }
434	      if (updateTranscriptFilter) updateTranscriptFilter();
435	    });
436	  }
437	
438	  const durationCard = document.getElementById("duration-stat-card");
439	  if (durationCard) {
440	    durationCard.addEventListener("click", () => {
441	      const chart = document.getElementById("duration-chart");
442	      const chevron = document.getElementById("duration-chevron");
443	      if (chart.style.display === "none") {
444	        chart.style.display = "block";
445	        chevron.style.transform = "rotate(90deg)";
446	        durationCard.style.borderColor = "#f59e0b";
447	      } else {
448	        chart.style.display = "none";
449	        chevron.style.transform = "rotate(0deg)";
450	        durationCard.style.borderColor = "var(--border-color)";
451	      }
452	    });
453	  }
454	}
