16	import { state, escapeHtml, syntaxHighlight, formatTime } from "./utils.js";
17	
18	export function renderTranscript(steps, container) {
19	  state.activeFilters = {
20	    userQueries: false,
21	    toolsCalled: false,
22	    outcomeErrors: false,
23	    modelResponses: false,
24	  };
25	  container.innerHTML = "";
26	
27	  if (!steps || steps.length === 0) {
28	    container.innerHTML =
29	      '<div class="empty-state">No transcript data found.</div>';
30	    return;
31	  }
32	
33	  const cards = steps.map((step, index) => {
34	    const isUserStep =
35	      step.source === "USER_EXPLICIT" || step.type === "USER_INPUT";
36	    const isErrorStep =
37	      step.status === "ERROR" ||
38	      step.type === "ERROR_MESSAGE" ||
39	      (step.type === "RUN_COMMAND" &&
40	        step.content &&
41	        step.content.includes("The command failed"));
42	    const isFinalModelResponse =
43	      step.source === "MODEL" &&
44	      (step.type === "PLANNER_RESPONSE" || step.type === "MESSAGE") &&
45	      step.content &&
46	      (!step.tool_calls || step.tool_calls.length === 0);
47	
48	    const card = document.createElement("div");
49	    let cardClass = "step-card";
50	    if (isUserStep) cardClass += " user-step";
51	    else if (isErrorStep) cardClass += " error-step";
52	    else if (isFinalModelResponse) cardClass += " final-response-step";
53	
54	    card.className = cardClass;
55	    if (step.created_at) {
56	      card.dataset.time = formatTime(step.created_at, false);
57	      const startMs = new Date(step.created_at).getTime();
58	      card.dataset.timestamp = startMs;
59	
60	      let endMs = startMs;
61	      if (step.content) {
62	        const match = step.content.match(/Completed At:\s*([^\n]+)/);
63	        if (match && match[1]) {
64	          const c = new Date(match[1].trim()).getTime();
65	          if (!isNaN(c)) endMs = Math.max(endMs, c);
66	        }
67	      }
68	      card.dataset.timestampEnd = endMs;
69	    }
70	
71	    card.style.animationDelay = `${Math.min(index * 0.015, 0.3)}s`;
72	
73	    let badgeClass = "system";
74	    if (step.source === "USER_EXPLICIT") {
75	      badgeClass = "user";
76	    } else if (step.source === "MODEL") {
77	      if (
78	        step.type &&
79	        step.type !== "PLANNER_RESPONSE" &&
80	        step.type !== "MESSAGE" &&
81	        step.type !== "ASK_QUESTION"
82	      ) {
83	        badgeClass = "tool";
84	      } else {
85	        badgeClass = "model";
86	      }
87	    } else if (
88	      step.type &&
89	      (step.type.includes("TOOL") ||
90	        step.type.includes("VIEW_FILE") ||
91	        step.type.includes("COMMAND"))
92	    ) {
93	      badgeClass = "tool";
94	    }
95	
96	    card.dataset.isUser = isUserStep ? "true" : "false";
97	    card.dataset.isTool =
98	      badgeClass === "tool" || (step.tool_calls && step.tool_calls.length > 0)
99	        ? "true"
100	        : "false";
101	    card.dataset.isError = isErrorStep ? "true" : "false";
102	    card.dataset.isModel = isFinalModelResponse ? "true" : "false";
103	
104	    const hasContent =
105	      step.content ||
106	      step.thinking ||
107	      step.error ||
108	      (step.tool_calls && step.tool_calls.length > 0);
109	
110	    const header = document.createElement("div");
111	    header.className = "step-header";
112	
113	    const typeStr = step.type || "UNKNOWN";
114	    const sourceStr = step.source || "UNKNOWN";
115	
116	    header.innerHTML = `
117	            <div style="display:flex; align-items:center; gap:12px;">
118	                ${
119	                  hasContent
120	                    ? '<span class="chevron">›</span>'
121	                    : '<span style="width:16px;"></span>'
122	                }
123	                <span class="badge ${badgeClass}">${sourceStr}</span>
124	                <span style="font-family:var(--font-mono); font-weight:500; font-size:0.9rem;">${typeStr}</span>
125	            </div>
126	            <div class="step-meta ${badgeClass}">${
127	      step.created_at
128	        ? `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg> ` +
129	          formatTime(step.created_at, true)
130	        : ""
131	    }</div>
132	        `;
133	
134	    card.appendChild(header);
135	
136	    if (!hasContent) {
137	      header.style.cursor = "default";
138	      return card;
139	    }
140	
141	    const body = document.createElement("div");
142	    body.className = "step-body collapsed";
143	
144	    header.style.cursor = "pointer";
145	    header.addEventListener("click", () => {
146	      const isCollapsed = body.classList.contains("collapsed");
147	      if (isCollapsed) {
148	        body.classList.remove("collapsed");
149	        header.querySelector(".chevron").style.transform = "rotate(90deg)";
150	      } else {
151	        body.classList.add("collapsed");
152	        header.querySelector(".chevron").style.transform = "rotate(0deg)";
153	      }
154	    });
155	
156	    let html = "";
157	    if (step.thinking) {
158	      html += `<div class="thought-box">${marked.parse(step.thinking)}</div>`;
159	    }
160	
161	    if (step.content) {
162	      let formattedContent;
163	      if (
164	        step.type === "USER_INPUT" ||
165	        step.type === "PLANNER_RESPONSE" ||
166	        step.type === "MESSAGE" ||
167	        step.type === "SEARCH_WEB"
168	      ) {
169	        let processedContent = step.content;
170	        if (step.type === "USER_INPUT") {
171	          let fileMap = {};
172	          const metadataMatch = processedContent.match(
173	            /<ADDITIONAL_METADATA>([\s\S]*?)<\/ADDITIONAL_METADATA>/
174	          );
175	          if (metadataMatch) {
176	            const metaContent = metadataMatch[1];
177	            const mentionRegex = /@\[(.*?)\] is a \[File\]:\n(.*?)(?=\n|$)/g;
178	            let m;
179	            while ((m = mentionRegex.exec(metaContent)) !== null) {
180	              fileMap[m[1]] = m[2].trim();
181	            }
182	
183	            processedContent = processedContent.replace(
184	              /@\[(.*?)\]/g,
185	              (match, filename) => {
186	                if (fileMap[filename]) {
187	                  return `[${match}](file://${fileMap[filename]})`;
188	                }
189	                return match;
190	              }
191	            );
192	          }
193	        }
194	
195	        if (step.type === "USER_INPUT" && processedContent.includes("<")) {
196	          let htmlParts = "";
197	          let hasTags = false;
198	          const tagRegex = /<([A-Z_]+)>([\s\S]*?)<\/\1>/g;
199	          let match;
200	          let lastIndex = 0;
201	          while ((match = tagRegex.exec(processedContent)) !== null) {
202	            hasTags = true;
203	            if (match.index > lastIndex) {
204	              const preText = processedContent
205	                .substring(lastIndex, match.index)
206	                .trim();
207	              if (preText)
208	                htmlParts += `<div class="user-request-block">${marked.parse(
209	                  preText
210	                )}</div>`;
211	            }
212	            const tagName = match[1];
213	            const tagContent = match[2].trim();
214	            if (tagName === "USER_REQUEST") {
215	              htmlParts += `<div class="user-request-block">${marked.parse(
216	                tagContent
217	              )}</div>`;
218	            } else {
219	              const niceName = tagName
220	                .split("_")
221	                .map((w) => w.charAt(0) + w.slice(1).toLowerCase())
222	                .join(" ");
223	              htmlParts += `<div class="system-context-block"><strong>${niceName}</strong><div class="system-context-content">${marked.parse(
224	                tagContent
225	              )}</div></div>`;
226	            }
227	            lastIndex = tagRegex.lastIndex;
228	          }
229	          if (lastIndex < processedContent.length) {
230	            const postText = processedContent.substring(lastIndex).trim();
231	            if (postText)
232	              htmlParts += `<div class="user-request-block">${marked.parse(
233	                postText
234	              )}</div>`;
235	          }
236	          formattedContent = `<div class="markdown-body">${
237	            hasTags ? htmlParts : marked.parse(processedContent)
238	          }</div>`;
239	        } else {
240	          let contentText = processedContent;
241	          let prefixHtml = "";
242	          if (step.type === "SEARCH_WEB") {
243	            // Extract standard tool metadata
244	            const metaRegex =
245	              /^(?:Created At:\s*(.*?)\n)?(?:Completed At:\s*(.*?)\n)?(?:Encountered error in step execution:\s*(.*?\n))?/;
246	            const match = contentText.match(metaRegex);
247	            if (match && match[0]) {
248	              contentText = contentText.substring(match[0].length).trim();
249	              const created = match[1];
250	              const completed = match[2];
251	              const errorMsg = match[3];
252	
253	              // Extract search phrase (e.g. "The search for "test" returned the following summary:")
254	              const searchPhraseRegex =
255	                /^The search for "(.*?)" returned the following summary:\n/i;
256	              const searchMatch = contentText.match(searchPhraseRegex);
257	              let searchPhrase = "";
258	              if (searchMatch) {
259	                searchPhrase = searchMatch[1].trim();
260	                contentText = contentText
261	                  .substring(searchMatch[0].length)
262	                  .trim();
263	              }
264	
265	              let metaHtml = `<div class="tool-meta-header" style="font-size:0.85em; color:var(--text-secondary); margin-bottom:12px; display:flex; flex-direction:column; gap:4px; padding-left:8px; border-left:2px solid rgba(148,163,184,0.3);">`;
266	              if (created && completed) {
267	                metaHtml += `<div>⏱ <strong>Duration:</strong> ${(
268	                  (new Date(completed) - new Date(created)) /
269	                  1000
270	                ).toFixed(1)}s</div>`;
271	              } else if (created) {
272	                metaHtml += `<div>⏱ <strong>Started:</strong> ${formatTime(
273	                  created,
274	                  true
275	                )}</div>`;
276	              }
277	              if (searchPhrase) {
278	                metaHtml += `<div>🔍 <strong>Query:</strong> ${escapeHtml(
279	                  searchPhrase
280	                )}</div>`;
281	              }
282	              if (errorMsg) {
283	                metaHtml += `<div style="color:#ef4444;">🚨 <strong>Error:</strong> ${escapeHtml(
284	                  errorMsg.trim()
285	                )}</div>`;
286	              }
287	              metaHtml += `</div>`;
288	              prefixHtml = metaHtml;
289	            }
290	
291	            // Extract URL map and format definitions dynamically
292	            let linkMap = {};
293	            const defRegex =
294	              /\[(\d+)\]\s*(?:\[.*?\]\((https?:\/\/[^\s\)]+)\)|(https?:\/\/[^\s\)]+))/g;
295	            let m;
296	            while ((m = defRegex.exec(contentText)) !== null) {
297	              linkMap[m[1]] = m[2] || m[3];
298	            }
299	
300	            // Replace inline references first, grouping adjacent citations into a single superscript
301	            const seqRegex = /(?:\[\d+\](?:\s*\[\d+\])*)/g;
302	            contentText = contentText.replace(
303	              seqRegex,
304	              (match, offset, str) => {
305	                const after = str.substring(offset + match.length);
306	                if (
307	                  after.match(/^\s*\[.*?\]\(http/) ||
308	                  after.match(/^\s*http/)
309	                ) {
310	                  return match; // It's a footer definition
311	                }
312	
313	                let ids = [];
314	                const idRegex = /\[(\d+)\]/g;
315	                let m;
316	                while ((m = idRegex.exec(match)) !== null) {
317	                  ids.push(m[1]);
318	                }
319	
320	                let linksHtml = ids
321	                  .map((id) => {
322	                    if (linkMap[id])
323	                      return `<a href="${linkMap[id]}" target="_blank" style="text-decoration:none; color:var(--accent-blue); font-weight:600;">${id}</a>`;
324	                    return id;
325	                  })
326	                  .join(", ");
327	
328	                return `<sup>${linksHtml}</sup>`;
329	              }
330	            );
331	
332	            // Now replace all footer definitions with markdown list items
333	            contentText = contentText.replace(
334	              /\[(\d+)\]\s*(?:\[.*?\]\((https?:\/\/[^\s\)]+)\)|(https?:\/\/[^\s\)]+))/g,
335	              "\n\n- $&"
336	            );
337	          }
338	          formattedContent =
339	            prefixHtml +
340	            `<div class="markdown-body">${marked.parse(contentText)}</div>`;
341	        }
342	      } else {
343	        let contentText = step.content;
344	        let metaHtml = "";
345	
346	        const metaRegex =
347	          /^(?:Created At:\s*(.*?)\n)?(?:Completed At:\s*(.*?)\n)?(?:Encountered error in step execution:\s*(.*?\n))?/;
348	        const match = contentText.match(metaRegex);
349	
350	        if (match && match[0]) {
351	          contentText = contentText.substring(match[0].length).trim();
352	          const created = match[1];
353	          const completed = match[2];
354	          const errorMsg = match[3];
355	
356	          let statusMsg = "";
357	          const statusRegex =
358	            /^\s*(The command (completed successfully\.|failed with exit code: \d+))/m;
359	          const statusMatch = contentText.match(statusRegex);
360	          if (statusMatch) {
361	            statusMsg = statusMatch[1];
362	            contentText = contentText.replace(statusMatch[0], "").trim();
363	          }
364	
365	          if (created || completed || errorMsg || statusMsg) {
366	            metaHtml = `<div class="tool-meta-header" style="font-size:0.85em; color:var(--text-secondary); margin-bottom:12px; display:flex; flex-direction:column; gap:4px; padding-left:8px; border-left:2px solid rgba(148,163,184,0.3);">`;
367	            if (created && completed) {
368	              metaHtml += `<div>⏱ <strong>Duration:</strong> ${(
369	                (new Date(completed) - new Date(created)) /
370	                1000
371	              ).toFixed(1)}s</div>`;
372	            } else if (created) {
373	              metaHtml += `<div>⏱ <strong>Started:</strong> ${formatTime(
374	                created,
375	                true
376	              )}</div>`;
377	            }
378	            if (statusMsg) {
379	              const isSuccess = statusMsg.includes("successfully");
380	              const icon = isSuccess ? "✅" : "❌";
381	              const color = isSuccess ? "#10b981" : "#ef4444"; // emerald green or red
382	              metaHtml += `<div style="color:${color};">${icon} <strong>Status:</strong> ${escapeHtml(
383	                statusMsg
384	              )}</div>`;
385	            }
386	            if (errorMsg) {
387	              metaHtml += `<div style="color:#ef4444;">🚨 <strong>Error:</strong> ${escapeHtml(
388	                errorMsg.trim()
389	              )}</div>`;
390	            }
391	            metaHtml += `</div>`;
392	          }
393	        }
394	
395	        // Clean up weird Antigravity framework indentation (up to 4 leading tabs)
396	        contentText = contentText.replace(/^\t{1,4}/gm, "");
397	
398	        // Remove superfluous wrapper labels
399	        contentText = contentText
400	          .replace(/^(?:Output|Stdout|Stderr):\s*\n?/gm, "")
401	          .trim();
402	
403	        if (!contentText) {
404	          formattedContent = metaHtml;
405	        } else {
406	          formattedContent = escapeHtml(contentText);
407	          try {
408	            const parsed = JSON.parse(contentText);
409	            if (typeof parsed === "object" && parsed !== null) {
410	              formattedContent = syntaxHighlight(
411	                JSON.stringify(parsed, null, 2)
412	              );
413	            }
414	          } catch (e) {}
415	          formattedContent =
416	            metaHtml + `<div class="code-block">${formattedContent}</div>`;
417	        }
418	      }
419	      html += formattedContent;
420	    }
421	
422	    if (step.error) {
423	      // Prevent rendering the big red box if the error was already captured and displayed in the metadata header
424	      const errorStr = escapeHtml(step.error.trim());
425	      if (!html.includes(errorStr)) {
426	        html += `<div class="code-block" style="color: #ef4444; border-color: #ef4444; background: rgba(239, 68, 68, 0.1); margin-top: 8px;"><strong>ERROR:</strong><br/>${errorStr}</div>`;
427	      }
428	    }
429	
430	    if (step.tool_calls && step.tool_calls.length > 0) {
431	      step.tool_calls.forEach((tool) => {
432	        html += `
433	                    <div class="tool-call">
434	                        <div class="tool-name">⚙ ${tool.name}</div>
435	                        <pre class="tool-args json-renderer">${syntaxHighlight(
436	                          JSON.stringify(tool.args, null, 2)
437	                        )}</pre>
438	                    </div>
439	                `;
440	      });
441	    }
442	
443	    body.innerHTML = html;
444	    card.appendChild(body);
445	    return card;
446	  });
447	
448	  let currentSequenceContainer = null;
449	  let currentStepsWrapper = null;
450	  let currentSequenceContent = null;
451	  let sequenceCounter = 1;
452	
453	  cards.forEach((card, index) => {
454	    const isUserStep = card.dataset.isUser === "true";
455	
456	    if (isUserStep || !currentSequenceContainer) {
457	      currentSequenceContainer = document.createElement("div");
458	      currentSequenceContainer.className = "sequence-wrapper";
459	      Object.assign(currentSequenceContainer.style, {
460	        marginBottom: "16px",
461	        background: "rgba(30, 41, 59, 0.3)",
462	        border: "1px solid rgba(148, 163, 184, 0.15)",
463	        borderRadius: "16px",
464	        padding: "16px",
465	        boxShadow:
466	          "0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)",
467	        transition: "all 0.3s ease",
468	      });
469	      if (card.dataset.timestamp) {
470	        currentSequenceContainer.dataset.timestampStart =
471	          card.dataset.timestamp;
472	        currentSequenceContainer.dataset.timestampEnd = card.dataset.timestamp;
473	      }
474	      container.appendChild(currentSequenceContainer);
475	
476	      const sequenceHeader = document.createElement("div");
477	      Object.assign(sequenceHeader.style, {
478	        display: "flex",
479	        alignItems: "center",
480	        gap: "8px",
481	        cursor: "pointer",
482	        marginBottom: "12px",
483	        color: "var(--text-secondary)",
484	        fontSize: "0.75rem",
485	        fontWeight: "600",
486	        letterSpacing: "0.05em",
487	        userSelect: "none",
488	      });
489	      let durationText = "";
490	      try {
491	        if (card.dataset.timestamp) {
492	          const startIndex = index;
493	          let endIndex = index;
494	          for (let i = index + 1; i < steps.length; i++) {
495	            if (cards[i] && cards[i].dataset.isUser === "true") {
496	              break;
497	            }
498	            endIndex = i;
499	          }
500	          if (endIndex > startIndex && cards[endIndex].dataset.timestamp) {
501	            const startMs = parseInt(card.dataset.timestamp, 10);
502	            const endMs = parseInt(cards[endIndex].dataset.timestamp, 10);
503	            currentSequenceContainer.dataset.timestampEnd = endMs;
504	
505	            const start = new Date(steps[index].created_at);
506	            const end = new Date(steps[endIndex].created_at);
507	            const diffMs = end - start;
508	            if (!isNaN(diffMs) && diffMs >= 0) {
509	              const diffSec = Math.floor(diffMs / 1000);
510	              const diffMin = Math.floor(diffSec / 60);
511	              const diffHour = Math.floor(diffMin / 60);
512	
513	              if (diffHour > 0) {
514	                durationText = ` · ⏱ ${diffHour}h ${diffMin % 60}m`;
515	              } else if (diffMin > 0) {
516	                durationText = ` · ⏱ ${diffMin}m ${diffSec % 60}s`;
517	              } else if (diffSec > 0) {
518	                durationText = ` · ⏱ ${diffSec}s`;
519	              } else {
520	                durationText = ` · ⏱ <1s`;
521	              }
522	            }
523	          }
524	        }
525	      } catch (e) {
526	        console.error("Error calculating duration", e);
527	      }
528	
529	      sequenceHeader.innerHTML = `
530	        <span class="seq-chevron" style="display:inline-block; transition: transform 0.2s; transform: rotate(90deg); font-size: 1.2rem; line-height: 1;">›</span>
531	        <span>Sequence ${sequenceCounter++}${durationText}</span>
532	      `;
533	      currentSequenceContainer.appendChild(sequenceHeader);
534	
535	      currentSequenceContent = document.createElement("div");
536	      currentSequenceContent.className = "sequence-content";
537	      currentSequenceContainer.appendChild(currentSequenceContent);
538	
539	      currentSequenceContent.appendChild(card);
540	
541	      currentStepsWrapper = document.createElement("div");
542	      currentStepsWrapper.className = "sequence-steps";
543	      Object.assign(currentStepsWrapper.style, {
544	        marginTop: "0",
545	      });
546	      currentSequenceContent.appendChild(currentStepsWrapper);
547	
548	      const localContent = currentSequenceContent;
549	      sequenceHeader.addEventListener("click", () => {
550	        const isCollapsed = localContent.style.display === "none";
551	        localContent.style.display = isCollapsed ? "block" : "none";
552	        sequenceHeader.querySelector(".seq-chevron").style.transform =
553	          isCollapsed ? "rotate(90deg)" : "rotate(0deg)";
554	        sequenceHeader.style.marginBottom = isCollapsed ? "12px" : "0";
555	      });
556	    } else {
557	      currentStepsWrapper.appendChild(card);
558	      if (card.dataset.timestamp) {
559	        currentSequenceContainer.dataset.timestampEnd = card.dataset.timestamp;
560	      }
561	    }
562	  });
563	
564	  const bottomMarker = document.createElement("div");
565	  bottomMarker.id = "timeline-bottom-marker";
566	  bottomMarker.style.height = "1px";
567	  bottomMarker.style.width = "100%";
568	  if (window.timelineStart && window.timelineTotalMs) {
569	    bottomMarker.dataset.timestamp =
570	      window.timelineStart + window.timelineTotalMs;
571	  }
572	  container.appendChild(bottomMarker);
573	
574	  window.dispatchEvent(new Event("transcriptLoaded"));
575	}
576	
577	window.scrollToTime = function (targetTimeMs) {
578	  const cards = Array.from(
579	    document.querySelectorAll(".step-card[data-timestamp]")
580	  );
581	  if (cards.length === 0) return;
582	
583	  let bestAfter = null;
584	  let minDiffAfter = Infinity;
585	  let bestBefore = null;
586	  let minDiffBefore = Infinity;
587	
588	  cards.forEach((c) => {
589	    const ts = parseInt(c.dataset.timestamp, 10);
590	    const diff = ts - targetTimeMs;
591	
592	    if (diff >= 0 && diff < minDiffAfter) {
593	      minDiffAfter = diff;
594	      bestAfter = c;
595	    } else if (diff < 0 && Math.abs(diff) < minDiffBefore) {
596	      minDiffBefore = Math.abs(diff);
597	      bestBefore = c;
598	    }
599	  });
600	
601	  // Bias towards showing the next step/sequence if we click exactly in a gap,
602	  // but fall back to the closest previous step if there are no steps after.
603	  const targetCard = bestAfter || bestBefore;
604	
605	  if (targetCard) {
606	    // Expand the sequence if it is collapsed
607	    const seqContent = targetCard.closest(".sequence-content");
608	    if (seqContent && seqContent.style.display === "none") {
609	      const seqHeader = seqContent.previousElementSibling;
610	      if (seqHeader) seqHeader.click();
611	    }
612	
613	    targetCard.scrollIntoView({ behavior: "smooth", block: "center" });
614	    targetCard.style.transition = "box-shadow 0.3s ease";
615	    targetCard.style.boxShadow =
616	      "0 0 0 2px var(--accent-blue), 0 0 20px rgba(96, 165, 250, 0.4)";
617	    setTimeout(() => {
618	      targetCard.style.boxShadow = "";
619	    }, 2000);
620	  }
621	};
