41	/**
42	 * Integration tests for {@link AnalysisController}, covering the "generate AI analysis" journey. The
43	 * LLM ({@link AnalyzerService}), the API-key accessor ({@link GeminiConfig}) and the token estimator
44	 * ({@link TokenCounter}) are replaced with deterministic mock beans so the orchestration, caching,
45	 * and error paths are exercised without any network access.
46	 */
47	@MicronautTest
48	class AnalysisControllerTest {
49	
50	    @Inject
51	    @Client("/")
52	    HttpClient client;
53	
54	    private static final ObjectMapper MAPPER = new ObjectMapper();
55	
56	    // Controllable mock state, shared with the @MockBean factory methods below.
57	    private static final AtomicReference<Optional<String>> API_KEY = new AtomicReference<>(
58	        Optional.of("test-key")
59	    );
60	    private static final AtomicInteger TOKEN_RESULT = new AtomicInteger(10);
61	    private static final List<String> ANALYZE_CALLS = new CopyOnWriteArrayList<>();
62	    private static final AtomicInteger CONSOLIDATE_CALLS = new AtomicInteger(0);
63	
64	    private static String originalUserHome;
65	    private static Path tempHome;
66	
67	    @BeforeAll
68	    static void setUpHome() throws IOException {
69	        originalUserHome = System.getProperty("user.home");
70	        tempHome = Files.createTempDirectory("agy-analysis-test-home");
71	        System.setProperty("user.home", tempHome.toString());
72	    }
73	
74	    @AfterAll
75	    static void restoreHome() {
76	        if (originalUserHome != null) {
77	            System.setProperty("user.home", originalUserHome);
78	        }
