16	package io.github.glaforge.agybrainviz;
17	
18	import dev.langchain4j.model.TokenCountEstimator;
19	import dev.langchain4j.model.google.genai.GoogleGenAiTokenCountEstimator;
20	import jakarta.inject.Inject;
21	import jakarta.inject.Singleton;
22	
23	/**
24	 * Estimates the number of tokens in a piece of text using the Google GenAI tokenizer.
25	 *
26	 * <p>The underlying {@link TokenCountEstimator} is built lazily on first use so that constructing
27	 * the bean (e.g. at application startup) never performs network I/O. Wrapping the estimator in a
28	 * bean lets tests replace token counting with a deterministic stub.
29	 *
30	 * <p>Because the estimator is built on first {@link #estimate(String)} call — which the analysis
31	 * pipeline invokes inside a try/catch that falls back to a character-length heuristic — a failure to
32	 * build the estimator (or to estimate) degrades to that heuristic rather than aborting the analysis.
33	 */
34	@Singleton
35	public class TokenCounter {
36	
37	    private final GeminiConfig config;
38	    private volatile TokenCountEstimator estimator;
39	
40	    @Inject
41	    public TokenCounter(GeminiConfig config) {
42	        this.config = config;
43	    }
44	
45	    /**
46	     * @param text the text to measure
47	     * @return the estimated token count for {@code text}
48	     */
49	    public int estimate(String text) {
50	        return delegate().estimateTokenCountInText(text);
51	    }
52	
53	    private TokenCountEstimator delegate() {
54	        TokenCountEstimator local = estimator;
55	        if (local == null) {
56	            synchronized (this) {
57	                local = estimator;
58	                if (local == null) {
59	                    local =
60	                        GoogleGenAiTokenCountEstimator
61	                            .builder()
62	                            .apiKey(config.apiKey().orElse("dummy"))
63	                            .modelName("gemini-3.5-flash")
64	                            .build();
65	                    estimator = local;
66	                }
67	            }
68	        }
69	        return local;
70	    }
71	}
